23	const PROCESSING_FEE = 5;
24	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
25	
26	const BASE_PREMIUMS: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	  staff: 80,
30	  potion: 40,
31	  rune: 25,
32	  moonstone: 25,
33	};
34	
35	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
36	const BLOCK_SIZE = 3;
37	const BLOCK_BASE_PREMIUM = 60;
38	const CURSE_SURCHARGE_RATE = 0.5;
39	const HIGH_ENCHANTMENT_THRESHOLD = 5;
40	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
41	
42	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
43	
44	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
45	
46	const componentGroupBasePremium = (type: string, count: number): number =>
47	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);
48	
49	const sumItemBasePremiums = (items: Item[]): number => {
50	  const componentCounts = new Map<string, number>();
51	  let total = 0;
52	  for (const item of items) {
53	    if (isComponent(item)) {
54	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
55	    } else {
56	      total += itemBasePremium(item);
57	    }
58	  }
59	  for (const [type, count] of componentCounts) {
60	    total += componentGroupBasePremium(type, count);
61	  }
62	  return total;
63	};
64	
65	const itemSurcharges = (item: Item): number => {
66	  const base = itemBasePremium(item);
67	  let surcharge = 0;
68	  if (item.cursed) surcharge += base * CURSE_SURCHARGE_RATE;
69	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD)
70	    surcharge += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
71	  return surcharge;
72	};
73	
74	const sumItemSurcharges = (items: Item[]): number =>
75	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
76	
77	const firstInsuranceSurchargeOn = (baseTotal: number): number =>
78	  baseTotal * FIRST_INSURANCE_SURCHARGE_RATE;
79	
80	const quoteStep = (step: QuoteStep): QuoteResult => {
81	  const baseTotal = sumItemBasePremiums(step.items);
82	  const itemSurchargesTotal = sumItemSurcharges(step.items);
83	  const policySurchargesTotal = firstInsuranceSurchargeOn(baseTotal);
84	  const premium = Math.ceil(
85	    baseTotal + itemSurchargesTotal + policySurchargesTotal + PROCESSING_FEE,
86	  );
87	  return { premium };
88	};
89	
90	export const runScenario = (scenario: Scenario): ScenarioResult => ({
91	  results: scenario.steps.map(quoteStep),
92	});
